before_code:
module decoder3to8 (
  input [2:0] select,
  output [7:0] decoded
);
  assign decoded = 8'b1 << select;
endmodule

module test_decoder;
  logic [2:0] sel;
  logic [7:0] out;
  decoder3to8 dec_inst (.select(sel), .output_data(out));
endmodule

after_code:
module decoder3to8 (
  input [2:0] select,
  output [7:0] decoded
);
  assign decoded = 8'b1 << select;
endmodule

module test_decoder;
  logic [2:0] sel;
  logic [7:0] out;
  decoder3to8 dec_inst (.select(sel), .decoded(out));
endmodule
